const d = $json;
const companyId = Number($('Webhook').first().json.body?.company_id ?? $('Webhook').first().json.company_id);
const hasTrn = Boolean(d?.e_invoicing || d?.vat);
const dimensions = [
  { key: 'fta_portal_registration', score: hasTrn ? 100 : 0 },
  { key: 'asp_accreditation', score: 50 },
  { key: 'erp_einvoicing_capability', score: 50 },
  { key: 'staff_training', score: 25 },
];
const overall = Math.round(dimensions.reduce((sum, x) => sum + x.score, 0) / dimensions.length);
let readiness = 'not_ready';
if (overall >= 75) readiness = 'ready';
else if (overall >= 40) readiness = 'partial';
const gap_areas = dimensions.filter(x => x.score < 75).map(x => `${x.key} below target`);
const recommendations = [
  'Assign ASP selection owner and shortlist accredited providers',
  'Run ERP capability fit-gap against UAE PINT AE requirements',
  'Schedule finance + tax training on e-invoicing processes'
];
return [{
  json: {
    company_id: companyId,
    assessed_at: new Date().toISOString(),
    overall_score: overall,
    readiness_level: readiness,
    gap_areas,
    recommendations,
    raw_payload: {
      dimensions,
      dashboard_summary: d
    }
  }
}];

const item = $input.first().json;
const score = item.readiness_score ?? item.overall_score ?? 0;
const gaps = item.gaps ?? item.gap_areas ?? [];
const recFromGaps = Array.isArray(gaps)
  ? gaps.map(g => (g && typeof g === 'object' && g.action != null) ? g.action : String(g))
  : [];
const payload = {
  company_id: item.company_id || 1,
  assessed_at: item.assessment_date ?? item.assessed_at,
  overall_score: score,
  readiness_level: item.readiness_level ?? (score >= 75 ? 'ready' : score >= 40 ? 'partial' : 'not_ready'),
  gap_areas: gaps,
  recommendations: item.recommendations ?? recFromGaps,
  raw_payload: item.raw_payload ?? {
    phase: item.phase,
    urgency: item.urgency_level ?? item.urgency,
    days_to_go_live: item.days_to_go_live,
  },
};
const body = JSON.stringify(payload);
return [{ json: { ...payload, _body: body } }];
